#include <bits/stdc++.h>
using namespace std;

int main(){
    int n,p=0;
    cin>>n;
    for(int i=0;i<n;i++){
    	int a,g,s,b,q;
    	cin>>a;
    	g=a%10;
    	s=a/10%10;
    	b=a/100%10;
    	q=a/1000;
        if (g-q-b-s>0){
            p++;
        }
    }
    cout<<p;
    return 0;
}
